  ('fire-eq-tech-moex-02500', 'fire-eq-tech', 'fire-eq-tech-moex-100-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '有關「防焰性能認證實施要點」之規定，下列何者錯誤？', '["防焰試驗合格號碼有效期限為2年", "窗簾、布幕，須經水洗及乾洗處理者，其試樣規格為3平方公尺以上", "地毯等地坪舖設物，其試樣規格為1平方公尺以上", "使用防焰標示之業者，每月使用防焰物品等狀況之紀錄，至少應保存10年"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:24+00:00", "source_pdf_sha1": "e0dea9d83693", "answer_pdf_sha1": "6427b1f6a133", "source_family": "moex-gov-tw", "moex": {"exam_code": "100090", "c": "902", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規概要", "year": "100", "exam_name": "100年專技引水、驗船、第1次食品技師、消防設備、地政士、專責報關、保險人員、特考中醫、語言治療、聽力、牙體技術考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
