  ('fire-eq-tech-moex-02506', 'fire-eq-tech', 'fire-eq-tech-moex-100-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依「消防法施行細則」規定，下列何者非屬消防法所稱之一定規模以上供公眾使用建築物？', '["總樓地板面積在三百平方公尺以上之百貨商場、超級市場及遊藝場等場所", "總樓地板面積在三百平方公尺以上之餐廳", "觀光旅館", "總樓地板面積在二百平方公尺以上之補習班"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:24+00:00", "source_pdf_sha1": "e0dea9d83693", "answer_pdf_sha1": "6427b1f6a133", "source_family": "moex-gov-tw", "moex": {"exam_code": "100090", "c": "902", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規概要", "year": "100", "exam_name": "100年專技引水、驗船、第1次食品技師、消防設備、地政士、專責報關、保險人員、特考中醫、語言治療、聽力、牙體技術考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
